@classmethod
def decide(cls, role: PlayerRole, state: GameState) -> int:
    ps = state.players[role]
    pipeline = sum(s.quantity for s in ps.incoming_shipments)
    position = ps.inventory - ps.backlog + pipeline
    return max(0, TARGET_INVENTORY + SAFETY_STOCK - position)
